# fmt: on


def skill_name(skill_id: int) -> str:
    return SKILL_NAMES.get(skill_id, f"Skill#{skill_id}")


def item_name(model_id: int) -> str:
    return ITEM_NAMES.get(model_id, f"Item#{model_id}")


def profession_name(prof_id: int) -> str:
    return PROFESSIONS.get(prof_id, f"Prof#{prof_id}")


def skill_type_name(type_id: int) -> str:
    return SKILL_TYPES.get(type_id, f"Type#{type_id}")


def item_type_name(type_id: int) -> str:
    return ITEM_TYPES.get(type_id, f"Type#{type_id}")
